      title: '',
      startDate: '',
      endDate: '',
      status: 'not-started',
      description: '',
      notes: ''
    });

    const [localTaskData, setLocalTaskData] = useState({
      title: '',
      value: 5,
      energy: 'medium',
      timeEstimate: 30,
      dueDate: '',
      notes: ''
