    // Handle pending edit task from Plan screen
    useEffect(() => {
      if (pendingEditTask && selectedProject) {
        setEditingProjectTask(pendingEditTask);
        setShowProjectTaskModal(true);
        setPendingEditTask(null); // Clear it after opening
