      'active': { bg: 'bg-emerald-500/20', text: 'text-emerald-400', label: 'Active' },
      'on-hold': { bg: 'bg-amber-500/20', text: 'text-amber-400', label: 'On Hold' },
      'completed': { bg: 'bg-purple-500/20', text: 'text-purple-400', label: 'Completed' }
