                            : e === 'medium' 
                              ? 'bg-amber-500/80 text-white shadow-lg shadow-amber-500/30' 
                              : 'bg-rose-500/80 text-white shadow-lg shadow-rose-500/30'
                          : 'bg-white/10 text-slate-400 hover:bg-white/20'}`}
                    >
                      {e === 'low' ? '🌱 Low' : e === 'medium' ? '⚡ Med' : '🔥 High'}
                    </button>
                  ))}
